#!/usr/bin/env python3
import subprocess
import sys
import os
from datetime import datetime

CERT_PATH = "/app/ssl/server.crt"

def main():
    # Check certificate exists
    if not os.path.isfile(CERT_PATH):
        print(f"ERROR: Certificate file not found at {CERT_PATH}")
        sys.exit(1)

    # Load and verify certificate using openssl
    try:
        result = subprocess.run(
            ["openssl", "x509", "-in", CERT_PATH, "-noout", "-text"],
            capture_output=True, text=True, check=True
        )
    except subprocess.CalledProcessError as e:
        print(f"ERROR: Failed to load certificate: {e}")
        sys.exit(1)

    # Extract Common Name
    cn = None
    for line in result.stdout.splitlines():
        if "Subject:" in line or "subject=" in line:
            if "CN" in line:
                cn = line.split("CN")[-1].strip().lstrip("/").strip()
                break

    # Extract expiration date
    expiry_str = None
    try:
        exp_result = subprocess.run(
            ["openssl", "x509", "-in", CERT_PATH, "-noout", "-enddate"],
            capture_output=True, text=True, check=True
        )
        for line in exp_result.stdout.strip().splitlines():
            if line.startswith("notAfter="):
                expiry_str = line.split("=", 1)[1].strip()
                break
    except subprocess.CalledProcessError:
        pass

    # Parse and format expiration date as YYYY-MM-DD
    expiry_date = None
    if expiry_str:
        try:
            dt = datetime.strptime(expiry_str, "%b %d %H:%M:%S %Y %Z")
            expiry_date = dt.strftime("%Y-%m-%d")
        except ValueError:
            try:
                dt = datetime.strptime(expiry_str, "%b  %d %H:%M:%S %Y %Z")
                expiry_date = dt.strftime("%Y-%m-%d")
            except ValueError:
                expiry_date = expiry_str

    # Print certificate details
    print("Certificate Details:")
    print(f"  Common Name (CN): {cn}")
    print(f"  Expiration Date: {expiry_date}")
    print()

    if cn and expiry_date:
        print("Certificate verification successful")
    else:
        print("ERROR: Could not extract required certificate details")
        sys.exit(1)

if __name__ == "__main__":
    main()
PYEOF
chmod +x /app/check_cert.py"}

